from matplotlib import pyplot as plt'''################################################################################################################################# Utils Functions ##################################################################################################################################'''def prepare_axes(ax=None, wavelength_range=None):    """    Initialize the figure and axis to plot    CRIRES+ settings.    Parameters    ----------    ax : plt Object    wavelength_range: list    """    if ax is None:        fig, ax = plt.subplots(figsize=(12, 6))    if wavelength_range is not None and not ax.has_data():        xmin, xmax = wavelength_range        padding = 0.06 * (xmax - xmin)        ax.set_xlim(xmin-padding, xmax+padding)            ax.set_ylim(0, 1.1)    return fig, ax    ##############################################    def update_xlim(ax, wavelength_range):    """    Update the x-axis to fit another CRIRES+ setting.    Parameters    ----------    ax : plt Object    wavelength_range: list    """    xmin, xmax = wavelength_range        padding = 0.06 * (xmax - xmin)    if not ax.has_data():        ax.set_xlim(xmin-padding, xmax+padding)        return    current_min, current_max = ax.get_xlim()    ax.set_xlim(        min(current_min, xmin-padding),        max(current_max, xmax+padding),    )    def update_ylim(ax, mol_num, spacing=0.05):    """    Update the x-axis to fit molecules emission range.    Parameters    ----------    ax : plt Object    mol_num: number of molecule plotted    spacing: spacing between molecules bar in the plot     """        top = 1.1 + mol_num * spacing    ax.set_ylim(0, top) ##############################################    def style_axes(ax):    ax.minorticks_on()    ax.tick_params(        axis="x",        which="major",        direction="inout",        length=5,    )    ax.tick_params(        axis="x",        which="minor",        direction="inout",        length=3,    )    ax.tick_params(        axis="y",        which="major",        direction="inout",        length=5,    )    ax.tick_params(        axis="y",        which="minor",        direction="inout",        length=3,    )##############################################def make_compact_axes(settings, figsize=(12, 6)):    """    Create one axis per CRIRES+ setting.    Parameters    ----------    settings : list[CRIRESSetting]    Returns    -------    fig : matplotlib.figure.Figure    axes : list[matplotlib.axes.Axes]    """    n = len(settings)            widths = [        s.wavelength_range[1] - s.wavelength_range[0]        for s in settings    ]    fig, axes = plt.subplots(        1,        n,        gridspec_kw={"width_ratios": widths, "wspace": 0.05,},        figsize=figsize,        sharey=True,        squeeze=False,    )    axes = axes.flatten()    for ax, setting in zip(axes, settings):        xmin, xmax = setting.wavelength_range        padding = 0.06 * (xmax - xmin)        ax.set_xlim(            xmin - padding,            xmax + padding,        )        ax.set_ylim(0, 1.1)            return fig, list(axes)##############################################def style_compact_axes(axes, settings, padding=0.02):    """    Apply a common style to all axes in a compact (broken-axis) plot.    """    for i, (ax, setting) in enumerate(zip(axes, settings)):        xmin, xmax = setting.wavelength_range        dx = xmax - xmin                ax.set_xlim(            xmin - padding*dx,            xmax + padding*dx,        )                        style_axes(ax)                if i!=0:            ax.spines["left"].set_visible(False)            ax.tick_params(axis="y", which="both", left=False, labelleft=False, length=0)        if(i!=len(axes)-1):            ax.spines["right"].set_visible(False)                        # Hide touching spines    for left, right in zip(axes[:-1], axes[1:]):        left.spines["right"].set_visible(False)        right.spines["left"].set_visible(False)                                  ##############################################        def add_break_marks(axes, size=0.02):    kwargs = dict(        color="k",        clip_on=False,        linewidth=1,    )    for left, right in zip(axes[:-1], axes[1:]):        # right edge of left axis        left.plot(            (1, 1),            (-size, +size),            transform=left.transAxes,            **kwargs,        )        left.plot(            (1, 1),            (1-size, 1+size),            transform=left.transAxes,            **kwargs,        )        # left edge of right axis        right.plot(            (0, 0),            (-size, +size),            transform=right.transAxes,            **kwargs,        )        right.plot(            (0, 0),            (1-size, 1+size),            transform=right.transAxes,            **kwargs,        )